/// Module for checking idempotency of operations.
pub struct IdempotencyChecker {
    executed_operations: std::collections::HashSet<String>,
}

impl IdempotencyChecker {
    pub fn new() -> Self {
        Self {
            executed_operations: std::collections::HashSet::new(),
        }
    }

    /// Execute an operation only once. Returns true if executed, false if already done.
    pub fn execute_once(&mut self, operation: &str, args: &str) -> bool {
        let key = format!("{}:{}", operation, args);
        if self.executed_operations.contains(&key) {
            return false;  // Already executed - skip
        }
        self.executed_operations.insert(key);
        true
    }

    /// Get count of unique operations executed.
    pub fn operation_count(&self) -> usize {
        self.executed_operations.len()
    }
}
